INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0b86b510-4024-4dc3-933c-76c56945dc9e',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt Security — When to Use bcrypt, Argon2, or scrypt$escape$,
  $escape$When securing JWT tokens, it's essential to use a password-based key derivation function (PBKDF) to protect against brute-force attacks. However, not all PBKDFs are created equal. In this context, bcrypt, Argon2, and scrypt are popular choices. Bcrypt is widely used but has been shown to be vulnerable to side-channel attacks. Argon2 is the winner of the Password Hashing Competition and is considered more secure. Scrypt is another option but can be slower than bcrypt. When using JWT, consider the trade-off between security and performance.$escape$,
  NULL,
  NULL,
