INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b188e4a1-d021-4410-b911-971a5b35c2ba',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt - Compliance with FIPS 140-2 and PCI-DSS Cryptography Requirements$escape$,
  $escape$When using jwt for authentication in a PCI-DSS compliant environment, it's essential to meet the cryptography requirements. This includes using FIPS 140-2 validated cryptographic modules. jwt uses the HS256 and RS256 algorithms, which are both FIPS 140-2 compliant. However, when using these algorithms, ensure that the key used for signing is also FIPS 140-2 validated. For HS256, the key is usually a shared secret, which must be securely stored and managed. For RS256, the key is a private RSA key, which must be generated and managed according to FIPS 140-2 guidelines.$escape$,
  NULL,
  NULL,
