INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36802d26-0e67-4d7e-9085-924a4e4f4e4a',
  '00000000-0000-0000-0000-000000000001',
  $escape$JWT Pitfalls — alg:none attack, expiry enforcement, storing tokens safely$escape$,
  $escape$Using an algorithm of `alg:none` in JSON Web Tokens (JWT) is a significant security risk due to the lack of encryption. An attacker can easily intercept and modify the token, compromising user authentication. To mitigate this, use a secure algorithm like `alg:HS256`. Additionally, ensure you enforce token expiry by setting a reasonable `exp` claim. Finally, never store JWTs in client-side storage like LocalStorage or cookies, as they can be accessed by malicious scripts. Instead, store them securely on the server-side using a secure token store.$escape$,
  NULL,
  NULL,
